def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            weight = (10 - j) / 45
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        if capacity > 3 * item:
            score *= 0.4
        elif capacity > 2 * item:
            score *= 0.6
        elif capacity > 1.5 * item:
            score *= 0.8
        elif capacity < item:
            score *= 2.5
        elif capacity < 0.8 * item:
            score *= 3
        else:
            score *= 1
        penalty = 0
        for k in range(1, 4):
            penalty += (item / (capacity + k)) * (0.1 * k)
        score += penalty
        if score > 1:
            score = np.log1p(score)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 15
    return priorities
